import React, { useState } from 'react';
import { LayoutDashboard, Users, Menu, X, Search, ChevronDown } from 'lucide-react';
import { MOCK_CLIENTS } from './constants';
import { ClientDetail } from './components/ClientDetail';
import { PlatformDashboard } from './components/PlatformDashboard';
import { ClientStage } from './types';

type ViewType = 'dashboard' | 'analysis';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [selectedClientId, setSelectedClientId] = useState<string>(MOCK_CLIENTS[0].id);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  const selectedClient = MOCK_CLIENTS.find(c => c.id === selectedClientId) || MOCK_CLIENTS[0];

  const filteredClients = MOCK_CLIENTS.filter(client => 
    client.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900 font-sans overflow-hidden">
      {/* Sidebar */}
      <div className={`${sidebarOpen ? 'w-64' : 'w-20'} bg-slate-900 text-white transition-all duration-300 flex-shrink-0 flex flex-col`}>
        <div className="p-5 flex items-center justify-between border-b border-slate-700">
          <div className={`font-bold text-lg flex items-center gap-2 ${!sidebarOpen && 'hidden'}`}>
             <div className="w-8 h-8 bg-blue-500 rounded-lg flex items-center justify-center">AI</div>
             AdInsight
          </div>
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-1 hover:bg-slate-700 rounded text-slate-400">
            {sidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto py-4">
           <div className="px-4 mb-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">菜单</div>
           <nav className="space-y-1 px-2">
             <button 
                onClick={() => setCurrentView('dashboard')}
                className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg transition-colors ${currentView === 'dashboard' ? 'bg-blue-600 text-white' : 'text-slate-300 hover:bg-slate-800 hover:text-white'}`}
            >
                <LayoutDashboard size={20} />
                {sidebarOpen && <span>大盘视图</span>}
             </button>
             <button 
                onClick={() => setCurrentView('analysis')}
                className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg transition-colors ${currentView === 'analysis' ? 'bg-blue-600 text-white' : 'text-slate-300 hover:bg-slate-800 hover:text-white'}`}
            >
                <Users size={20} />
                {sidebarOpen && <span>客户分析</span>}
             </button>
           </nav>
        </div>

        <div className="p-4 border-t border-slate-700">
            <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-xs">JD</div>
                {sidebarOpen && (
                    <div>
                        <div className="text-sm font-medium">John Doe</div>
                        <div className="text-xs text-slate-500">高级商务经理</div>
                    </div>
                )}
            </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 overflow-y-auto flex flex-col">
        <header className="bg-white border-b border-gray-200 h-16 flex items-center justify-between px-8 sticky top-0 z-20 shadow-sm">
           <div className="flex items-center gap-4">
               <h2 className="font-semibold text-gray-700 text-lg">
                   {currentView === 'dashboard' ? '全域大盘监控' : '客户深度洞察'}
               </h2>
           </div>

           <div className="flex items-center gap-4">
              <span className="text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded">最后更新: 刚刚</span>
           </div>
        </header>

        {/* Sub Header for Analysis View - Search Bar */}
        {currentView === 'analysis' && (
            <div className="bg-white border-b border-gray-200 px-8 py-4">
                <div className="max-w-7xl mx-auto">
                    <label className="block text-sm font-medium text-gray-700 mb-2">选择要分析的客户</label>
                    <div className="relative max-w-lg">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <Search size={18} className="text-gray-400" />
                        </div>
                        <select 
                            value={selectedClientId}
                            onChange={(e) => setSelectedClientId(e.target.value)}
                            className="block w-full pl-10 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm rounded-md border"
                        >
                            {MOCK_CLIENTS.map(client => (
                                <option key={client.id} value={client.id}>
                                    {client.name} — {client.stage === ClientStage.ACTIVE ? '活跃' : client.stage === ClientStage.PROSPECT ? '拓展' : '流失'}
                                </option>
                            ))}
                        </select>
                        <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                            <ChevronDown size={16} className="text-gray-400" />
                        </div>
                    </div>
                </div>
            </div>
        )}

        <main className="p-8 flex-1 bg-gray-50">
            {currentView === 'dashboard' ? (
                <PlatformDashboard />
            ) : (
                <ClientDetail client={selectedClient} />
            )}
        </main>
      </div>
    </div>
  );
};

export default App;
